const orcamento = $json.body || {};
const calc = orcamento.dimensionamento_backup_calculado || {};
const dados_eletricos = orcamento.dados_eletricos || {};

const simultanea_kw = calc.potencia_critica_simultanea_kw || 0;
const margem_tecnica = (calc.paramentos_calculo || {}).margem_tecnica || 0.25;

// Potência mínima do inversor
const potencia_inversor_minima_kw = Number((simultanea_kw * (1 + margem_tecnica)).toFixed(3));

let inversor_sugerido = 'Cascata/Múltiplos Inversores Híbridos (Requer Avaliação Técnica)';
let compatibilidade_valida = true;
const pendencias_inversor = [];

const fase = dados_eletricos.tipo_ligacao || 'trifasico';

if (fase === 'monofasico' || fase === 'bifasico') {
  if (potencia_inversor_minima_kw <= 5.0) {
    inversor_sugerido = 'SolaX X1-Hybrid 5.0-D';
  } else {
    compatibilidade_valida = false;
    pendencias_inversor.push(`Potência de backup calculada (${potencia_inversor_minima_kw} kW) excede limite monofásico/bifásico padrão de 5 kW. Requer alteração do padrão do cliente para trifásico.`);
  }
} else if (fase === 'trifasico') {
  if (potencia_inversor_minima_kw <= 10.0) {
    inversor_sugerido = 'SolaX X3-Hybrid 10.0-D';
  } else if (potencia_inversor_minima_kw <= 15.0) {
    inversor_sugerido = 'SolaX X3-Hybrid 15.0-D';
  } else {
    inversor_sugerido = 'Múltiplos Inversores SolaX X3 Híbridos em Cascata';
    pendencias_inversor.push(`Potência calculada (${potencia_inversor_minima_kw} kW) requer múltiplos inversores integrados em paralelo.`);
  }
}

return {
  ...orcamento,
  dimensionamento_backup_calculado: {
    ...calc,
    potencia_inversor_minima_kw,
    inversor_sugerido,
    compatibilidade_valida,
    pendencias_inversor
  },
  status: 'calculado_inversor'
};
